-- The goal is to show that the function `fun ω ↦ (wignerMatrixMap n ω) i j` has law `μ` under `WignerMeasure`.
-- This requires showing that the function is equal to `fun ω ↦ ω ⟨min i j, max i j⟩` and that this function has law `μ`.
have h1 : (fun ω ↦ (wignerMatrixMap n ω) i j) = fun ω ↦ ω ⟨min i j, max i j⟩ := by
  funext ω
  simp [wignerMatrixMap, wignerMatrixEntryFunction]
  cases lt_or_gt_of_ne h with
  | inl h_lt =>
    simp [h_lt, min_eq_left, max_eq_right]
    all_goals try { rfl }
  | inr h_gt =>
    simp [h_gt, min_eq_right, max_eq_left]
    all_goals try { rfl }
rw [h1]
-- Now we need to show that (fun ω ↦ ω ⟨min i j, max i j⟩) has law μ under WignerMeasure
-- This involves unfolding definitions and using properties of product measures
have h2 : (⟨min i j, max i j⟩ : Fin n × Fin n).1 ≠ (⟨min i j, max i j⟩ : Fin n × Fin n).2 := by
  intro h_eq
  cases min_eq_max_iff.1 h_eq with
  | inl h_lt_eq => 
    exfalso; exact h (Ne.symm (NeZero.ne (Fin.mk.injEq (by linarith))))
  | inr h_lt_eq => 
    exfalso; exact h (Ne.symm (NeZero.ne (Fin.mk.injEq (by linarith))))
-- Now connect this to the law of the function
apply MeasureTheory.Measure.map_has_law
simp [WignerMeasure, wignerMeasureDist, h2]
